function makeSlug($t){$s=mb_strtolower($t,'UTF-8');$tr=['а'=>'a','б'=>'b','в'=>'v','г'=>'g','д'=>'d','е'=>'e','ё'=>'yo','ж'=>'zh','з'=>'z','и'=>'i','й'=>'y','к'=>'k','л'=>'l','м'=>'m','н'=>'n','о'=>'o','п'=>'p','р'=>'r','с'=>'s','т'=>'t','у'=>'u','ф'=>'f','х'=>'h','ц'=>'ts','ч'=>'ch','ш'=>'sh','щ'=>'sch','ъ'=>'','ы'=>'y','ь'=>'','э'=>'e','ю'=>'yu','я'=>'ya'];$s=strtr($s,$tr);$s=preg_replace('/[^a-z0-9]+/','-',$s);return trim($s,'-');}
function seo($t,$i,$w,$a,$a1,$a2){$l=implode('',array_map(fn($x)=>'<li>'.$x.'</li>',$a));return '<p><strong>Всероссийская олимпиада «'.$t.'»</strong> — '.$i.'.</p><h3>Что вас ждёт</h3><p>'.$w.'.</p><h3>Кому подойдёт</h3><ul>'.$l.'</ul><h3>Преимущества участия</h3><ul><li>Участие <strong>полностью бесплатное</strong> — проходите тест в удобное время</li><li>Диплом I, II или III степени для портфолио при аттестации — 169 руб.</li><li>'.$a1.'</li><li>'.$a2.'</li></ul>';}
function ins($db,$o,&$ord){$slug=makeSlug($o['title']);$c=$db->prepare("SELECT id FROM olympiads WHERE slug=?");$c->execute([$slug]);if($c->fetch()){echo "  SKIP: {$o['title']}\n";return null;}$st=$db->prepare("INSERT INTO olympiads (title,slug,description,seo_content,target_audience,subject,grade,diploma_price,is_active,display_order) VALUES(?,?,?,?,?,?,NULL,169.00,1,?)");$st->execute([$o['title'],$slug,$o['desc'],$o['seo'],$o['ta'],$o['subj'],$ord]);$id=$db->lastInsertId();$ord++;foreach($o['questions'] as $i=>$q){$db->prepare("INSERT INTO olympiad_questions (olympiad_id,question_text,options,correct_option_index,display_order) VALUES(?,?,?,?,?)")->execute([$id,$q[0],json_encode($q[1],JSON_UNESCAPED_UNICODE),$q[2],$i+1]);}foreach($o['at'] as $a){$db->prepare("INSERT IGNORE INTO olympiad_audience_types (olympiad_id,audience_type_id) VALUES(?,?)")->execute([$id,$a]);}$db->prepare("INSERT IGNORE INTO olympiad_audience_categories (olympiad_id,category_id) VALUES(?,?)")->execute([$id,$o['cat']]);$db->prepare("INSERT IGNORE INTO olympiad_specializations (olympiad_id,specialization_id) VALUES(?,?)")->execute([$id,$o['spec']]);echo "  OK #$id: {$o['title']}\n";return $id;}

